def count_words(text: str) -> dict:
    chars = len(text)
    chinese = sum(1 for c in text if '一' <= c <= '鿿')
    words = len(text.split())
    lines = text.count('\n') + 1
    return {"chars": chars, "chinese_chars": chinese, "words": words, "lines": lines}

